#include "test_framework.hpp"
#include "mst/mst.hpp"
#include <string>

using namespace cryo;
using namespace cryo_test;

namespace {

void add_nodes(Graph& g, size_t count) {
    for (size_t i = 0; i < count; i++) {
        g.add_node_with_id(i);
    }
}

void assert_connected_mst_parity(const Graph& g, const std::string& ctx) {
    auto km = kruskal(g);
    auto pm = prim(g, 0);
    auto bm = boruvka(g);

    assert_near(bm.total_weight, km.total_weight, 1e-9, ctx + " vs kruskal");
    assert_near(bm.total_weight, pm.total_weight, 1e-9, ctx + " vs prim");
    assert_eq(bm.edges.size(), g.node_count() - 1, ctx + " edge count");
    assert_true(is_spanning_tree(g, bm), ctx + " spanning tree");
    assert_false(bm.is_forest, ctx + " forest flag");
}

Graph deterministic_connected_graph(size_t n) {
    Graph g(GraphType::Undirected);
    add_nodes(g, n);

    for (size_t i = 0; i < n; i++) {
        for (size_t j = i + 1; j < n; j++) {
            double weight = static_cast<double>(((i + 3) * (j + 5)) % 17 + 1);
            g.add_edge(i, j, weight);
        }
    }

    return g;
}

} // namespace

CRYO_TEST(MST, BoruvkaConsidersBothEndpointComponents) {
    Graph g(GraphType::Undirected);
    add_nodes(g, 4);

    g.add_edge(0, 1, 1.0);
    g.add_edge(0, 2, 1.0);
    g.add_edge(0, 3, 1.0);
    g.add_edge(1, 2, 2.0);

    auto bm = boruvka(g);
    assert_near(bm.total_weight, 3.0);
    assert_connected_mst_parity(g, "one-sided regression");
}

CRYO_TEST(MST, BoruvkaEqualWeightEdges) {
    Graph g(GraphType::Undirected);
    add_nodes(g, 4);

    g.add_edge(0, 1, 1.0);
    g.add_edge(0, 2, 1.0);
    g.add_edge(0, 3, 1.0);
    g.add_edge(1, 2, 1.0);
    g.add_edge(1, 3, 1.0);
    g.add_edge(2, 3, 1.0);

    assert_connected_mst_parity(g, "equal weights");
    assert_near(boruvka(g).total_weight, 3.0);
}

CRYO_TEST(MST, BoruvkaMultipleComponentsCanMergeInOnePhase) {
    Graph g(GraphType::Undirected);
    add_nodes(g, 6);

    g.add_edge(0, 1, 1.0);
    g.add_edge(1, 2, 2.0);
    g.add_edge(2, 3, 1.0);
    g.add_edge(3, 4, 2.0);
    g.add_edge(4, 5, 1.0);
    g.add_edge(0, 5, 10.0);
    g.add_edge(1, 4, 9.0);

    assert_connected_mst_parity(g, "multi-merge");
    assert_near(boruvka(g).total_weight, 7.0);
}

CRYO_TEST(MST, BoruvkaSingleNodeGraph) {
    Graph g(GraphType::Undirected);
    g.add_node_with_id(0);

    auto bm = boruvka(g);
    assert_true(bm.edges.empty());
    assert_near(bm.total_weight, 0.0);
    assert_false(bm.is_forest);
    assert_true(is_spanning_tree(g, bm));
}

CRYO_TEST(MST, BoruvkaDisconnectedGraphMatchesKruskalForestWeight) {
    Graph g(GraphType::Undirected);
    add_nodes(g, 6);

    g.add_edge(0, 1, 1.0);
    g.add_edge(1, 2, 1.0);
    g.add_edge(0, 2, 4.0);
    g.add_edge(3, 4, 5.0);

    auto km = kruskal(g);
    auto bm = boruvka(g);

    assert_true(bm.is_forest);
    assert_false(is_spanning_tree(g, bm));
    assert_eq(bm.edges.size(), km.edges.size());
    assert_near(bm.total_weight, km.total_weight);
    assert_near(bm.total_weight, 7.0);
}

CRYO_TEST(MST, BoruvkaTotalWeightParityAcrossConnectedInputs) {
    for (size_t n = 2; n <= 8; n++) {
        auto g = deterministic_connected_graph(n);
        assert_connected_mst_parity(g, "complete deterministic n=" + std::to_string(n));
    }
}

